import React from 'react';

const techSkills = [
  { category: 'Cloud Platforms', accent: '#0078d4', icon: '☁️', items: ['AWS', 'Azure AZ-900', 'Azure AZ-104', 'Microsoft Entra ID', 'Azure Active Directory'] },
  { category: 'Security & Compliance', accent: '#c23b22', icon: '🔒', items: ['Microsoft Defender', 'Microsoft Purview', 'Security Incident Response', 'ISC2 CC'] },
  { category: 'Endpoint & Device Mgmt', accent: '#107c10', icon: '💻', items: ['Microsoft Intune', 'SCCM', 'Knox Management', 'Flexera Snow', 'Troubleshooting Windows', 'iOS', 'Linux'] },
  { category: 'Microsoft 365 Administration', accent: '#d83b01', icon: '📊', items: ['Teams Admin', 'Defender', 'Exchange', 'Purview', 'AppDynamics', 'Zscaler ELK', 'Thousand Eyes'] },
  { category: 'Business Applications', accent: '#5c2d91', icon: '🏢', items: ['Microsoft FinOps Administration', 'Dynamics 365 Retail & Hardware Setup', 'SAP C/4HANA', 'CRM Tools', 'EFTPOS / POS Systems', 'Payment Gateway Troubleshooting'] },
  { category: 'Scripting & Automation', accent: '#005b70', icon: '⚙️', items: ['PowerShell Scripting & Automation', 'Active Directory', 'ITIL Service Management', 'License Management', 'Network Configuration & Device Management'] },
  { category: 'IT Service & Operations', accent: '#6b3a2a', icon: '🛠️', items: ['Project Planning & Execution', 'Handling Internal User IT Requests', 'Managing & Auditing Third-Party Vendor Accounts', 'User Onboarding & Offboarding', 'IT Asset Management'] },
];

const softSkills = [
  'Collaborative team player across cross-functional teams',
  'Strong communication and customer service',
  'Self-motivated and positive thinking',
  'Efficient time management and task prioritisation',
  'Attention to detail in system configuration and hardware setup',
  'Adaptable to new technologies and rapidly changing environments',
  'Excellent problem-solving and critical thinking',
];

const SectionTitle: React.FC<{ title: string; count?: string }> = ({ title, count }) => (
  <div style={{ marginBottom: 16 }}>
    <div style={{ display: 'flex', alignItems: 'baseline', gap: 10 }}>
      <h3 style={{ fontSize: 15, fontWeight: 'bold', color: '#000080' }}>{title}</h3>
      {count && <span style={{ fontSize: 10, color: '#999', letterSpacing: 1 }}>{count}</span>}
    </div>
    <div style={{ height: 2, background: 'linear-gradient(90deg, #000080 0%, #e0e0e0 100%)', marginTop: 4 }} />
  </div>
);

const Skills: React.FC = () => (
  <div style={{ padding: '28px 32px', overflowY: 'auto', background: '#fff' }}>

    {/* ── 1. TECHNICAL SKILLS ── */}
    <SectionTitle title="Technical Skills" count={`${techSkills.reduce((a, g) => a + g.items.length, 0)} SKILLS`} />
    <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 36 }}>
      {techSkills.map(group => (
        <div key={group.category} style={{
          display: 'flex', alignItems: 'flex-start',
          border: '1px solid #e8e8e8', overflow: 'hidden',
        }}>
          <div style={{
            width: 180, flexShrink: 0, background: group.accent,
            padding: '10px 14px', display: 'flex', alignItems: 'center', gap: 8,
          }}>
            <span style={{ fontSize: 14 }}>{group.icon}</span>
            <span style={{ fontSize: 11, fontWeight: 'bold', color: '#fff', lineHeight: 1.3 }}>{group.category}</span>
          </div>
          <div style={{
            flex: 1, padding: '8px 12px',
            display: 'flex', flexWrap: 'wrap', gap: 6,
            background: '#fafafa', alignContent: 'center',
          }}>
            {group.items.map(item => (
              <span key={item} style={{
                padding: '3px 10px', fontSize: 11,
                background: '#fff', border: `1px solid ${group.accent}50`, color: '#333',
              }}>{item}</span>
            ))}
          </div>
        </div>
      ))}
    </div>

    {/* ── 2. SOFT SKILLS ── */}
    <SectionTitle title="Soft Skills" count={`${softSkills.length} TRAITS`} />
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
      {softSkills.map((skill, i) => (
        <div key={i} style={{
          display: 'flex', alignItems: 'flex-start', gap: 10,
          padding: '9px 12px', background: '#fafafa',
          border: '1px solid #e8e8e8', borderLeft: '3px solid #000080',
        }}>
          <span style={{ fontSize: 14, flexShrink: 0, marginTop: 1 }}>✓</span>
          <span style={{ fontSize: 11, color: '#333', lineHeight: 1.5 }}>{skill}</span>
        </div>
      ))}
    </div>

  </div>
);

export default Skills;
